// Asset module declarations (Metro resolves these to asset ids at bundle time).
declare module '*.ttf' {
  const content: number
  export default content
}
declare module '*.png' {
  const content: number
  export default content
}
declare module '*.jpg' {
  const content: number
  export default content
}
declare module '*.jpeg' {
  const content: number
  export default content
}
